import React from 'react';
import HeaderInfo from './components/HeaderInfo';
import HeaderNavigator from './components/HeaderNavigator';

import './Header.css';
import './HeaderNavigator.css';
import './HeaderInfo.css';

class Header extends React.Component {
    constructor(props) {
      super(props);
      this.state = {
        currentPageName: props.currentPageName || 'Home'
      };
    }

    render() {
        return (
            <header>
                <HeaderInfo currentPageName={this.state.currentPageName}
                    githubURL="www.github.com"
                    githubPagesURL="www.github.com"
                    domainName="www.unix69.github.io"
                    headerInfoClass="header-info"
                    headerInfoDomainInfoClass="header-info-domain-info"
                    headerInfoDomainLogoClass="header-info-domain-logo"
                    headerInfoDomainUrlClass="header-info-domain-url"
                    headerInfoGitHubInfoClass="header-info-github-info"
                    headerInfoGitHubUrlClass="header-info-github-url"
                    headerInfoGitHubLogoClass="header-info-github-logo"
                    headerInfoGitHubPagesUrlClass="header-info-github-pages-url"
                    headerInfoGitHubPagesLogoClass="header-info-github-pages-logo"
                    headerInfoBackgroundImageClass="header-info-background-image"
                    headerInfoCurrentPageClass="header-info-current-page"
                />
                <HeaderNavigator class="header-navigator"/>
            </header>
        )
    }
};

export default Header;
